import{c as e,bj as o,aQ as d,aT as a}from"./chunks/framework.BSLq2HW8.js";const g=JSON.parse('{"title":"Mail Accounts","description":"","frontmatter":{},"headers":[],"relativePath":"documentation/local-server/mail-accounts.md","filePath":"documentation/local-server/mail-accounts.md","lastUpdated":1772776319000}'),r={name:"documentation/local-server/mail-accounts.md"};function n(c,t,s,i,l,m){return o(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="mail-accounts" tabindex="-1">Mail Accounts <a class="header-anchor" href="#mail-accounts" aria-label="Permalink to “Mail Accounts”">​</a></h1><p>Configure and manage the email accounts used for automated mail operations through the Local Server.</p><h2 id="adding-account" tabindex="-1">➕ Adding an Account <a class="header-anchor" href="#adding-account" aria-label="Permalink to “➕ Adding an Account”">​</a></h2><p>To add a new email account, click the <strong>+ Add Account</strong> button. You will need to provide the following details:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Account Name</strong></td><td>A friendly name to identify the account (e.g., &quot;Primary Gmail&quot;).</td></tr><tr><td><strong>IMAP Host</strong></td><td>The IMAP server address (e.g., <code>imap.gmail.com</code>).</td></tr><tr><td><strong>IMAP Port</strong></td><td>The port for IMAP connections (e.g., <code>993</code>).</td></tr><tr><td><strong>SMTP Host</strong></td><td>The SMTP server address (e.g., <code>smtp.gmail.com</code>).</td></tr><tr><td><strong>SMTP Port</strong></td><td>The port for SMTP connections (e.g., <code>587</code>).</td></tr><tr><td><strong>Email Address</strong></td><td>The full email address of the account.</td></tr><tr><td><strong>App Password</strong></td><td>The application-specific password (required for Gmail and other providers).</td></tr></tbody></table><h3 id="common-email-provider-settings" tabindex="-1">Common Email Provider Settings <a class="header-anchor" href="#common-email-provider-settings" aria-label="Permalink to “Common Email Provider Settings”">​</a></h3><p>Use these settings for popular email services. Note that for most services, you must use an <strong>App Password</strong> instead of your regular password.</p><table tabindex="0"><thead><tr><th>Provider</th><th>IMAP Host</th><th>IMAP Port</th><th>SMTP Host</th><th>SMTP Port</th></tr></thead><tbody><tr><td><strong>Gmail</strong></td><td><code>imap.gmail.com</code></td><td><code>993</code></td><td><code>smtp.gmail.com</code></td><td><code>587</code> or <code>465</code></td></tr><tr><td><strong>Yahoo</strong></td><td><code>imap.mail.yahoo.com</code></td><td><code>993</code></td><td><code>smtp.mail.yahoo.com</code></td><td><code>465</code> or <code>587</code></td></tr><tr><td><strong>Outlook</strong></td><td><code>outlook.office365.com</code></td><td><code>993</code></td><td><code>smtp.office365.com</code></td><td><code>587</code></td></tr><tr><td><strong>iCloud</strong></td><td><code>imap.mail.me.com</code></td><td><code>993</code></td><td><code>smtp.mail.me.com</code></td><td><code>587</code></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>Always ensure that <strong>IMAP Access</strong> is enabled in your email provider&#39;s settings before attempting to connect. Search <code>&quot;How to enable IMAP on gmail account&quot;</code></p></div><h2 id="account-management" tabindex="-1">🛠️ Account Management <a class="header-anchor" href="#account-management" aria-label="Permalink to “🛠️ Account Management”">​</a></h2><p>Once an account is added, it will appear as a card in the <strong>Mail Accounts</strong> list. Each card features several actions on the right side:</p><table tabindex="0"><thead><tr><th>Action</th><th>Icon</th><th>Description</th></tr></thead><tbody><tr><td><strong>Test IMAP</strong></td><td>🔄</td><td>Verifies the receiving settings by attempting to connect to the IMAP server.</td></tr><tr><td><strong>Test SMTP</strong></td><td>🚀</td><td>Verifies the sending settings by attempting to connect to the SMTP server.</td></tr><tr><td><strong>Edit Account</strong></td><td>✏️</td><td>Opens the account configuration modal to update settings.</td></tr><tr><td><strong>Delete Account</strong></td><td>🗑️</td><td>Removes the account from the Local Server.</td></tr><tr><td><strong>View Emails</strong></td><td>➡️</td><td>Opens the email viewer for this specific account.</td></tr></tbody></table><h2 id="other-actions" tabindex="-1">📝 Other Actions <a class="header-anchor" href="#other-actions" aria-label="Permalink to “📝 Other Actions”">​</a></h2><ul><li><strong>Compose</strong>: Opens a window to manually write and send an email through the selected account.</li></ul>',14)])])}const u=e(r,[["render",n]]);export{g as __pageData,u as default};
